// Extrai leads do Supabase
const leads = $input.all().map(item => item.json);

// Filtra leads de hoje (simulado ou baseado na data de criacao)
const hoje = new Date().toISOString().split('T')[0];
const novos = leads.filter(l => l.data_criacao && l.data_criacao.startsWith(hoje)).length;

// Metricas gerais
const aprovados = leads.filter(l => l.status === 'aprovado').length;
const pendentes = leads.filter(l => l.status === 'pendente' || l.status === 'em_negociacao').length;

// Bairros
const bairros = {};
leads.forEach(l => {
  if(l.bairro) {
    bairros[l.bairro] = (bairros[l.bairro] || 0) + 1;
  }
});
const topBairros = Object.entries(bairros).sort((a,b) => b[1] - a[1]).slice(0,3).map(b => b[0]).join(', ') || 'N/A';

// Gargalos
let gargalos = 'Sem gargalos identificados.';
if (pendentes > 15) {
  gargalos = 'Alto numero de leads pendentes no funil. Necessario follow-up intenso.';
} else if (aprovados === 0 && novos > 10) {
  gargalos = 'Baixa conversao de novos leads. Revisar abordagens de Avaliação Técnica.';
}

// Monta o resumo para a Diretoria (Diogo/Raphael)
const mensagem = `📊 *Relatório Comercial Diário - DL Nexus*\n\n📈 *Métricas:*\n- Novos Leads (Hoje): ${novos}\n- Propostas Aprovadas: ${aprovados}\n- Leads Pendentes: ${pendentes}\n\n📍 *Melhores Bairros (Volume):*\n- ${topBairros}\n\n⚠️ *Análise de Gargalos:*\n- ${gargalos}\n\n_A Avaliação Técnica para leads avançados deve ser avaliada pelo Tecnólogo Responsável._`;

return [{ json: { mensagem } }];
